// One-off parse benchmark for lib.dom.d.ts (Go native parser).
package main

import (
	"fmt"
	"os"
	"time"

	"github.com/microsoft/typescript-go/internal/ast"
	"github.com/microsoft/typescript-go/internal/core"
	"github.com/microsoft/typescript-go/internal/parser"
	"github.com/microsoft/typescript-go/internal/tspath"
	"github.com/microsoft/typescript-go/internal/vfs/osvfs"
)

func main() {
	path := "/Users/bytedance/dev/typescript-go/internal/bundled/libs/lib.dom.d.ts"
	data, err := os.ReadFile(path)
	if err != nil {
		panic(err)
	}
	fileName := tspath.GetNormalizedAbsolutePath(path, "/")
	p := tspath.ToPath(fileName, "/", osvfs.FS().UseCaseSensitiveFileNames())
	opts := ast.SourceFileParseOptions{FileName: fileName, Path: p}
	kind := core.GetScriptKindFromFileName(fileName)

	// warmup
	parser.ParseSourceFile(opts, string(data), kind)

	const n = 5
	var total time.Duration
	for i := 0; i < n; i++ {
		start := time.Now()
		parser.ParseSourceFile(opts, string(data), kind)
		total += time.Since(start)
	}
	fmt.Printf("Go parser.ParseSourceFile lib.dom.d.ts (%d bytes): median ~%.3fs (%d runs)\n",
		len(data), total.Seconds()/float64(n), n)
}

